queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCriteria ?child ; p:hasScholarships ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Scholarships } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?value WHERE {
  ?scholarship_criteria a :Scholarship_Criteria .
  ?criteria a :Criteria .
  ?scholarship_criteria p:hasCriteria ?criteria .
  ?scholarships a :Scholarships .
  ?scholarship_criteria p:hasScholarships ?scholarships .
  ?scholarships p:name ?name .
  ?criteria p:value ?value .
} }
  collective: { SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCriteria ?child ; p:hasScholarships ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Scholarships } }
  FILTER(?nf = ?total)
} }
}
